import { useState } from "react";
import Header from "./Header";
import { TodoModal, AlertModal } from "./Modal";
import TodoBox from "./TodoBox";
import "./App.css";

export default function App() {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [toggleAlert, setToggleAlert] = useState(false);
    const [todos, setTodos] = useState([]);

    const handleModal = function () {
        setIsModalOpen(!isModalOpen);
    };
    const handleAlert = function () {
        setToggleAlert(!toggleAlert);
    };

    return (
        <div className="App">
            <Header />
            <TodoBox handleModal={handleModal} todos={todos} />
            <TodoModal isModalOpen={isModalOpen} handleModal={handleModal} setTodos={setTodos} />
            <AlertModal isModalOpen={toggleAlert} handleAlert={handleAlert} />
        </div>
    );
}
